+/** Configuration support for {@linkcode Command}. */
+
+/** Options used to locate and read a command configuration file. */
+export interface ConfigOptions {
+  /** Base name of the configuration file (without its format suffix). */
+  name: string;
+  /** Directories to search. Defaults to the current working directory. */
+  searchPaths?: string[];
+  /** Formats to search, in order. Defaults to JSON then RC. */
+  formats?: string[];
+  /** Merge files from every search path instead of using the first match. */
+  mergeConfigs?: boolean;
+  /** Optional parser for a configuration file's text. */
+  parser?: (content: string) => Record<string, unknown>;
+}
+
+/** Thrown when a configuration file cannot be parsed. */
+export class ConfigParseError extends Error {
+  constructor(path: string, cause?: unknown) {
+    super(`Failed to parse configuration file "${path}".`, { cause });
+    Object.setPrototypeOf(this, ConfigParseError.prototype);
+  }
+}
+
+/** Thrown when a known configuration value is incompatible with its option. */
+export class ConfigValidationError extends Error {
+  constructor(key: string, message: string) {
+    super(`Invalid configuration value for "${key}": ${message}`);
+    Object.setPrototypeOf(this, ConfigValidationError.prototype);
+  }
+}
+
+export interface LoadedConfig {
+  path?: string;
+  values: Record<string, unknown>;
+}
+
+function camelCase(key: string): string {
+  return key.replace(/-([a-zA-Z0-9])/g, (_, char) => char.toUpperCase());
+}
+
+function flatten(value: Record<string, unknown>, prefix = ""): Record<string, unknown> {
+  const result: Record<string, unknown> = {};
+  for (const [key, item] of Object.entries(value)) {
+    const name = prefix ? `${prefix}.${camelCase(key)}` : camelCase(key);
+    if (item !== null && typeof item === "object" && !Array.isArray(item)) {
+      Object.assign(result, flatten(item as Record<string, unknown>, name));
+    } else {
+      result[name] = item;
+    }
+  }
+  return result;
+}
+
+function parseRc(content: string): Record<string, unknown> {
+  const values: Record<string, unknown> = {};
+  for (const line of content.split(/\\r?\
/)) {
+    const trimmed = line.trim();
+    if (!trimmed || trimmed.startsWith("#")) continue;
+    const separator = trimmed.indexOf("=");
+    if (separator < 0) throw new Error("Expected key=value pair.");
+    const key = camelCase(trimmed.slice(0, separator).trim());
+    let value = trimmed.slice(separator + 1).trim();
+    if (value.startsWith('"') && value.endsWith('"') && value.length >= 2) {
+      value = value.slice(1, -1);
+    } else if (value === "true") {
+      values[key] = true;
+      continue;
+    } else if (value === "false") {
+      values[key] = false;
+      continue;
+    } else if (value !== "" && /^[-+]?(?:\\d+\\.?\\d*|\\.\\d+)$/.test(value)) {
+      values[key] = Number(value);
+      continue;
+    }
+    values[key] = value;
+  }
+  return values;
+}
+
+function filename(name: string, format: string): string {
+  return format === ".rc" ? `.${name}rc` : `${name}${format}`;
+}
+
+async function readFile(path: string): Promise<string | undefined> {
+  // dnt-shim-ignore
+  const { Deno } = globalThis as any;
+  try {
+    if (Deno) return await Deno.readTextFile(path);
+    const { readFile } = await import("node:fs/promises");
+    return await readFile(path, "utf8");
+  } catch (error) {
+    if ((error as { code?: string }).code === "ENOENT" ||
+      (error as { name?: string }).name === "NotFound") return;
+    throw error;
+  }
+}
+
+/** Locate and parse configuration files. */
+export async function loadConfig(options: ConfigOptions): Promise<LoadedConfig> {
+  // dnt-shim-ignore
+  const { Deno, process } = globalThis as any;
+  const paths = options.searchPaths ?? [Deno?.cwd?.() ?? process?.cwd?.() ?? "."];
+  const formats = options.formats ?? [".json", ".rc"];
+  const loaded: LoadedConfig[] = [];
+
+  for (const directory of paths) {
+    for (const format of formats) {
+      const path = `${directory.replace(/[\\\\/]$/, "")}/${filename(options.name, format)}`;
+      const content = await readFile(path);
+      if (content === undefined) continue;
+      try {
+        const parsed = options.parser ? options.parser(content) : format === ".rc"
+          ? parseRc(content)
+          : JSON.parse(content);
+        if (!parsed || Array.isArray(parsed) || typeof parsed !== "object") {
+          throw new Error("Configuration must be a plain object.");
+        }
+        loaded.push({ path, values: flatten(parsed) });
+      } catch (error) {
+        throw new ConfigParseError(path, error);
+      }
+      break;
+    }
+    if (loaded.length && !options.mergeConfigs) break;
+  }
+
+  if (!options.mergeConfigs) return loaded[0] ?? { values: {} };
+  // Earlier search paths take precedence.
+  return {
+    path: loaded[0]?.path,
+    values: Object.assign({}, ...loaded.reverse().map((config) => config.values)),
+  };
+}
