+  private parseConfigValue(key: string, value: unknown, option: Option): unknown {
+    const argument = option.args[0];
+    const parse = (item: unknown): unknown => {
+      if (!argument) {
+        if (typeof item !== "boolean") {
+          throw new ConfigValidationError(key, "expected a boolean");
+        }
+        return item;
+      }
+      if (argument.type === "boolean" && typeof item !== "boolean") {
+        throw new ConfigValidationError(key, "expected a boolean");
+      }
+      if ((argument.type === "number" || argument.type === "integer") &&
+        typeof item !== "number") {
+        throw new ConfigValidationError(key, `expected a ${argument.type}`);
+      }
+      if (argument.type === "string" && typeof item !== "string") {
+        throw new ConfigValidationError(key, "expected a string");
+      }
+      try {
+        return this.parseType({
+          label: "Configuration",
+          type: argument.type,
+          name: key,
+          value: String(item),
+        });
+      } catch (error) {
+        throw new ConfigValidationError(
+          key,
+          error instanceof Error ? error.message : String(error),
+        );
+      }
+    };
+
+    if (Array.isArray(value)) {
+      if (!(option as Option & { collect?: boolean }).collect) {
+        throw new ConfigValidationError(key, "expected a single value");
+      }
+      return value.map(parse);
+    }
+    const parsed = parse(value);
+    return option.value ? option.value(parsed) : parsed;
+  }
